// ── A9: Location Intelligence Engine ─────────────────────────────────────────
// Accepts combined output from the Master Orchestrator (all A1-A8 data merged)
// Returns: saturation score, opportunity score, viability score, GO/CAUTION/NO

const body = $input.first().json.body || $input.first().json;

// ── Unpack A1 v4 competitor intelligence ─────────────────────────────────────
const competitors      = Array.isArray(body.competitors)      ? body.competitors      : [];
const opportunityLevel = String(body.opportunity_level        || 'unknown');
const strongCount      = parseInt(body.strong_count           || 0);
const moderateCount    = parseInt(body.moderate_count         || 0);
const weakCount        = parseInt(body.weak_count             || 0);
const totalCount       = parseInt(body.validated_count        || competitors.length || 0);
const searchRadiusM    = parseInt(body.search_radius_m        || 600);
const bizKey           = String(body.biz_key || body.bizKey   || 'other').toLowerCase();
const area             = String(body.area                     || '');
const city             = String(body.city                     || '');
const reportId         = String(body.reportId || body.report_id || '');
const businessType     = String(body.businessType || body.business_type || bizKey);

// ── Unpack A2 location signals ────────────────────────────────────────────────
const monthlyRent   = parseFloat(body.monthly_rent   || body.median_rent   || 0);
const footfallRaw   = String(body.footfall_signal    || body.foot_traffic   || '').toLowerCase();
const transitRaw    = String(body.transit_signal     || body.public_transport || '').toLowerCase();
const anchorCount   = Array.isArray(body.nearby_anchors) ? body.nearby_anchors.length : 0;

// ── Unpack A3 market demand ───────────────────────────────────────────────────
const demandScore    = parseFloat(body.market_score  || body.demand_score   || 0) || null;
const demandTrend    = String(body.demand_trend       || body.trend          || 'stable').toLowerCase();

// ── Unpack A4/A5 financial snapshot ──────────────────────────────────────────
const projRevenue    = parseFloat(body.estimated_monthly_revenue || body.monthly_revenue || 0) || null;

// ─────────────────────────────────────────────────────────────────────────────
// STEP 1: MARKET SATURATION SCORE (0–100)
// Higher = more saturated = harder to enter
// Weighted by threat severity: strong competitors hurt more than weak ones
// ─────────────────────────────────────────────────────────────────────────────
const satRaw = (strongCount * 25) + (moderateCount * 12) + (weakCount * 4);
const saturationScore = Math.min(100, Math.round(satRaw));

// Saturation band
const saturationBand =
  saturationScore >= 75 ? 'very_high'
: saturationScore >= 50 ? 'high'
: saturationScore >= 25 ? 'moderate'
: totalCount === 0      ? 'unknown'
: 'low';

// ─────────────────────────────────────────────────────────────────────────────
// STEP 2: MARKET OPPORTUNITY SCORE (0–100)
// Higher = more room in the market = better for new entrant
// ─────────────────────────────────────────────────────────────────────────────
let opportunityScore = 100 - saturationScore;  // base: inverse of saturation

// Demand adjustment: growing market = more opportunity despite saturation
if (demandTrend === 'growing')     opportunityScore += 12;
if (demandTrend === 'stable')      opportunityScore +=  4;
if (demandTrend === 'declining')   opportunityScore -= 15;

// Footfall adjustment
if (footfallRaw.includes('high'))  opportunityScore +=  8;
if (footfallRaw.includes('low'))   opportunityScore -= 10;

// Demand score adjustment (relative to neutral 50)
if (demandScore !== null) {
  opportunityScore += Math.round((demandScore - 50) * 0.15);
}

opportunityScore = Math.round(Math.max(0, Math.min(100, opportunityScore)));

// ─────────────────────────────────────────────────────────────────────────────
// STEP 3: LOCATION VIABILITY SCORE (0–100)
// Composite: opportunity (40%) + demand attractiveness (35%) + location signals (25%)
// ─────────────────────────────────────────────────────────────────────────────
let locationSignalScore = 50; // neutral base
if (footfallRaw.includes('high'))   locationSignalScore += 20;
if (footfallRaw.includes('medium')) locationSignalScore += 10;
if (footfallRaw.includes('low'))    locationSignalScore -= 15;
if (transitRaw.includes('excellent') || transitRaw.includes('strong')) locationSignalScore += 15;
if (transitRaw.includes('good'))    locationSignalScore += 8;
if (transitRaw.includes('poor'))    locationSignalScore -= 8;
if (anchorCount >= 3)               locationSignalScore += 10;
locationSignalScore = Math.round(Math.max(0, Math.min(100, locationSignalScore)));

const demandAttractiveness = demandScore !== null
  ? Math.round(
      (demandScore / 10) * 60
      + (demandTrend === 'growing'  ?  20 : 0)
      + (demandTrend === 'declining' ? -15 : 0)
    )
  : 50; // neutral when no A3 data

const viabilityScore = Math.round(
  Math.max(0, Math.min(100,
    (opportunityScore      * 0.40) +
    (demandAttractiveness  * 0.35) +
    (locationSignalScore   * 0.25)
  ))
);

// ─────────────────────────────────────────────────────────────────────────────
// STEP 4: DETECT MARKET GAP
// What specific opportunity does this location offer?
// ─────────────────────────────────────────────────────────────────────────────
let marketGapNote = null;

if (totalCount === 0 && opportunityLevel === 'unknown') {
  marketGapNote = 'No ' + businessType + ' operators detected within ' + searchRadiusM + 'm of ' + area + '. Verify locally — this may indicate an underserved market or a data gap.';
} else if (strongCount === 0 && totalCount > 0) {
  marketGapNote = 'No dominant operator in this market — ' + totalCount + ' competitor(s) found but none are strongly established. First-mover with quality product has an advantage.';
} else if (strongCount >= 1 && moderateCount === 0 && weakCount === 0) {
  marketGapNote = 'One strong operator dominates — a niche or premium positioning could carve out a distinct customer segment.';
} else if (saturationBand === 'low' || saturationBand === 'unknown') {
  marketGapNote = 'Low competitive density within ' + searchRadiusM + 'm. Market appears underserved for ' + businessType + ' in ' + area + '.';
}

// ─────────────────────────────────────────────────────────────────────────────
// STEP 5: IDENTIFY TOP THREATS (top 3 by threat_score)
// ─────────────────────────────────────────────────────────────────────────────
const sorted = competitors.slice().sort(function(a, b) {
  return (b.threat_score || 0) - (a.threat_score || 0);
});

const topThreats = sorted.slice(0, 3).map(function(c) {
  return {
    name:         c.name         || 'Unknown',
    rating:       c.rating       || null,
    threat_score: c.threat_score || null,
    threat_label: c.threat_label || null,
    rank:         c.rank         || null,
    distance_m:   c.distance_m   || null,
    address:      c.address      || null
  };
});

// ─────────────────────────────────────────────────────────────────────────────
// STEP 6: VERDICT — GO / CAUTION / NO
// ─────────────────────────────────────────────────────────────────────────────
let verdict;
let verdictConfidence;

if (opportunityLevel === 'unknown') {
  // No confirmed competitor data — cannot make confident call
  verdict           = 'CAUTION';
  verdictConfidence = 'low';
} else if (viabilityScore >= 65 && saturationBand !== 'very_high') {
  verdict           = 'GO';
  verdictConfidence = viabilityScore >= 80 ? 'high' : 'medium';
} else if (viabilityScore >= 38 || opportunityLevel === 'medium') {
  verdict           = 'CAUTION';
  verdictConfidence = 'medium';
} else {
  verdict           = 'NO';
  verdictConfidence = saturationBand === 'very_high' ? 'high' : 'medium';
}

// ─────────────────────────────────────────────────────────────────────────────
// STEP 7: REASONING (specific, not generic)
// ─────────────────────────────────────────────────────────────────────────────
const reasons = [];

// Competition finding
if (totalCount === 0) {
  reasons.push('No competitors detected within ' + searchRadiusM + 'm — verify data before treating as blue ocean');
} else if (strongCount >= 3) {
  reasons.push(strongCount + ' well-established competitors within ' + searchRadiusM + 'm — market is crowded');
} else if (strongCount === 0) {
  reasons.push(totalCount + ' competitor(s) found but none are strongly established — entry window is open');
} else {
  reasons.push(totalCount + ' competitor(s) including ' + strongCount + ' strong operator(s) within ' + searchRadiusM + 'm');
}

// Demand
if (demandTrend === 'growing') {
  reasons.push('Market demand is growing — favourable timing for entry in ' + area);
} else if (demandTrend === 'declining') {
  reasons.push('Market demand is declining in ' + area + ' — increased risk for new ' + businessType + ' operator');
} else {
  reasons.push('Market demand is stable in ' + area);
}

// Footfall / location
if (footfallRaw.includes('high')) {
  reasons.push('High foot traffic on this street — strong natural discovery potential');
} else if (footfallRaw.includes('low')) {
  reasons.push('Low foot traffic requires active marketing investment to drive awareness');
}

// Rent
if (monthlyRent > 0 && projRevenue && projRevenue > 0) {
  const rentPct = Math.round((monthlyRent / projRevenue) * 100);
  if (rentPct > 30) {
    reasons.push('Rent at ' + rentPct + '% of projected revenue is above the 20% sustainable threshold');
  } else {
    reasons.push('Rent at ' + rentPct + '% of projected revenue is within sustainable range');
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// STEP 8: CONDITIONS AND FAILURE MODES
// ─────────────────────────────────────────────────────────────────────────────
const conditions = [];
const failureModes = [];

if (strongCount >= 1) {
  conditions.push('Must differentiate clearly from ' + topThreats.map(function(t) { return t.name; }).join(', '));
}
if (monthlyRent > 8000) {
  conditions.push('Monthly revenue must exceed AUD ' + (monthlyRent * 3).toLocaleString() + ' to maintain healthy rent-to-revenue ratio');
}
if (demandTrend === 'stable' || demandTrend === 'declining') {
  conditions.push('Marketing investment required to capture share from existing operators — organic demand is not growing');
}

if (saturationBand === 'high' || saturationBand === 'very_high') {
  failureModes.push('A second strong competitor opening nearby would push this location into loss');
}
if (demandTrend === 'declining') {
  failureModes.push('Continued demand decline shrinks total addressable market below minimum viable size');
}
if (opportunityLevel === 'unknown') {
  failureModes.push('Competitor data was incomplete — actual market may be more saturated than detected');
}

// ─────────────────────────────────────────────────────────────────────────────
// ASSEMBLE OUTPUT
// ─────────────────────────────────────────────────────────────────────────────
return [{
  json: {
    // Verdict
    verdict:              verdict,
    verdict_confidence:   verdictConfidence,
    verdict_summary:
      verdict === 'GO'      ? 'Strong commercial viability — proceed with execution plan' :
      verdict === 'CAUTION' ? 'Viable with conditions — address key risks before committing' :
                              'Not recommended — competitive or demand conditions are unfavourable',

    // Scores
    saturation_score:         saturationScore,
    saturation_band:          saturationBand,
    opportunity_score:        opportunityScore,
    demand_attractiveness:    Math.max(0, Math.min(100, demandAttractiveness)),
    location_signal_score:    locationSignalScore,
    viability_score:          viabilityScore,

    // Market intelligence
    opportunity_level:        opportunityLevel,
    market_gap_note:          marketGapNote,
    top_threats:              topThreats,

    // Competitor summary
    strong_competitor_count:  strongCount,
    moderate_competitor_count: moderateCount,
    weak_competitor_count:    weakCount,
    total_competitor_count:   totalCount,
    search_radius_m:          searchRadiusM,

    // Reasoning
    verdict_reasons:          reasons,
    conditions_for_success:   conditions,
    failure_modes:            failureModes,

    // Context
    business_type:            businessType,
    area:                     area,
    city:                     city,
    report_id:                reportId,
    analysed_at:              new Date().toISOString()
  }
}];
